import { createTheme, ThemeProvider } from '@mui/material/styles';
import { SignUpComponent } from '../Components/SignUpComponent';



const theme = createTheme();

export default function SignUpPage() {
  return (
    <ThemeProvider theme={theme}>
          <SignUpComponent/>
    </ThemeProvider>
  );
}
